const root = $input.first().json;
const evt = root.body ?? root;
const run = evt.workflow_run;

if (!run || evt.action !== 'completed') return [];

const failedConclusions = new Set(['failure', 'timed_out', 'cancelled', 'action_required']);
if (!failedConclusions.has(run.conclusion)) return [];

const pullRequests = run.pull_requests || [];
if (!pullRequests.length) return [];

return [{ json: { ...evt, pull_request: pullRequests[0] } }];

const evt = $('Filter Failed Runs').first().json;
const run = evt.workflow_run;
const repo = evt.repository;
const pr = evt.pull_request;
const response = $input.first().json;
const jobs = Array.isArray(response.jobs) ? response.jobs : [];

const failedJobs = jobs
  .filter(job => ['failure', 'timed_out', 'cancelled', 'action_required'].includes(job.conclusion))
  .map(job => ({
    name: job.name,
    conclusion: job.conclusion,
    html_url: job.html_url,
    started_at: job.started_at,
    completed_at: job.completed_at,
    failed_steps: (job.steps || [])
      .filter(step => ['failure', 'timed_out', 'cancelled', 'action_required'].includes(step.conclusion))
      .map(step => ({
        name: step.name,
        number: step.number,
        conclusion: step.conclusion,
        started_at: step.started_at,
        completed_at: step.completed_at
      }))
  }));

const context = {
  owner: repo.owner.login,
  repo: repo.name,
  pr_number: pr.number,
  run_id: run.id,
  run_name: run.name,
  run_number: run.run_number,
  run_attempt: run.run_attempt,
  conclusion: run.conclusion,
  event: run.event,
  branch: run.head_branch,
  sha: run.head_sha,
  actor: run.actor?.login,
  html_url: run.html_url,
  jobs_url: run.jobs_url,
  failed_jobs: failedJobs
};

if (!failedJobs.length) {
  context.failed_jobs = [{
    name: '(No failed jobs returned by GitHub jobs API)',
    conclusion: run.conclusion,
    html_url: run.html_url,
    failed_steps: []
  }];
}

return [{ json: context }];

const context = $('Build Failure Context').first().json;
const agent = $input.first().json;
let comment = String(agent.output || agent.text || '').trim();

if (!comment) {
  comment = `## CI Failure Summary

**Likely cause:** The workflow failed, but the AI explainer returned an empty response.

**Failed workflow:** ${context.run_name} #${context.run_number}, branch ${context.branch}, commit ${String(context.sha || '').slice(0, 12)}.

**Failed jobs**
- Metadata unavailable.

**Recommended next actions**
1. Open the failed run and inspect the first failed job.
2. Check the failed step output in GitHub Actions.
3. Re-run the workflow after applying a fix.

**Links**
- [Failed run](${context.html_url})`;
}

comment = comment.replace(/@everyone/g, '@​everyone');
comment = comment.replace(/@here/g, '@​here');

const MAX = 12000;
if (comment.length > MAX) {
  comment = comment.slice(0, MAX) + '

_Comment truncated by workflow before posting to GitHub._';
}

return [{ json: { ...context, comment } }];
